function isWellFormed(s) {
    let stack = [];
    for (let i = 0; i < s.length; i++) {
        if (s[i] === '<' && s[i + 1] === 'l' && s[i + 2] === 'i') {
            stack.push(s[i + 3]);
        } else if (s[i] === '<' && s[i + 1] === '/' && s[i + 2] === 'l' && s[i + 3] === 'i') {
            stack.pop();
        }
    }
    return stack.length === 0;
}

