class Solution:
    def is_well_formed(self, s: str) -> bool:
        stack = []
        for i in range(len(s)):
            if s[i] == '<' and s[i + 1] == 'l' and s[i + 2] == 'i':
                stack.append(s[i + 3])
            elif s[i] == '<' and s[i + 1] == '/' and s[i + 2] == 'l' and s[i + 3] == 'i':
                stack.pop()
        return len(stack) == 0
